import React, { useState } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { Menu, X, User, Instagram, Facebook } from 'lucide-react';
import { SIMPLECONSIGN_LINK, INSTAGRAM_LINK, FACEBOOK_LINK } from '../constants';

const Navbar: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const location = useLocation();

  const navLinks = [
    { name: 'HOME', path: '/' },
    { name: 'NEW ARRIVALS', path: '/new-arrivals' },
    { name: 'ABOUT', path: '/about' },
    { name: 'CONTACT', path: '/contact' },
  ];

  const isActive = (path: string) => location.pathname === path;

  return (
    <nav className="sticky top-0 z-50 bg-white shadow-sm border-b border-gray-100">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between h-24 items-center">
          {/* Logo */}
          <Link to="/" className="flex flex-col items-center">
            <span className="text-3xl font-serif font-bold text-gray-800 tracking-tight leading-none">
              Consigning <span className="text-fuchsia-brand italic">Women</span>
            </span>
            <span className="text-[10px] uppercase tracking-[0.2em] font-medium text-gray-500 mt-1">
              Upscale Resale Boutique
            </span>
          </Link>

          {/* Desktop Navigation */}
          <div className="hidden md:flex items-center space-x-8">
            {navLinks.map((link) => (
              <Link
                key={link.path}
                to={link.path}
                className={`text-sm font-semibold tracking-wider hover:text-fuchsia-brand transition-colors ${
                  isActive(link.path) ? 'text-fuchsia-brand border-b-2 border-fuchsia-brand pb-1' : 'text-gray-600'
                }`}
              >
                {link.name}
              </Link>
            ))}

            <a
              href={SIMPLECONSIGN_LINK}
              target="_blank"
              rel="noopener noreferrer"
              className="flex items-center gap-2 bg-fuchsia-brand text-white px-5 py-2.5 rounded-full text-sm font-bold shadow-md hover:bg-[#AD1457] transition-all transform hover:scale-105"
            >
              <User size={18} />
              MY ACCOUNT
            </a>

            <div className="flex items-center space-x-4 border-l border-gray-200 pl-6 ml-2">
              <a href={INSTAGRAM_LINK} target="_blank" rel="noopener noreferrer" className="text-gray-400 hover:text-fuchsia-brand">
                <Instagram size={20} />
              </a>
              <a href={FACEBOOK_LINK} target="_blank" rel="noopener noreferrer" className="text-gray-400 hover:text-fuchsia-brand">
                <Facebook size={20} />
              </a>
            </div>
          </div>

          {/* Mobile menu button */}
          <div className="md:hidden flex items-center">
            <button
              onClick={() => setIsOpen(!isOpen)}
              className="text-gray-600 hover:text-fuchsia-brand focus:outline-none"
            >
              {isOpen ? <X size={28} /> : <Menu size={28} />}
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Navigation */}
      {isOpen && (
        <div className="md:hidden bg-white border-t border-gray-100 py-4 px-6 space-y-4 shadow-lg absolute w-full top-24 left-0 animate-in fade-in slide-in-from-top-4 duration-300">
          {navLinks.map((link) => (
            <Link
              key={link.path}
              to={link.path}
              onClick={() => setIsOpen(false)}
              className={`block text-lg font-medium ${
                isActive(link.path) ? 'text-fuchsia-brand' : 'text-gray-600'
              }`}
            >
              {link.name}
            </Link>
          ))}
          <a
            href={SIMPLECONSIGN_LINK}
            target="_blank"
            rel="noopener noreferrer"
            className="flex items-center justify-center gap-2 bg-fuchsia-brand text-white w-full py-4 rounded-xl text-lg font-bold"
          >
            <User size={20} />
            MY ACCOUNT
